import pandas as pd
from modules import counting  
from modules import inference 
from modules import visualise

# Replace these with your actual filenames
INPUT_FASTA = "dummy_spike_sequences.fasta"
# You must paste the full 3822bp sequence here for the math to work
REFERENCE_SEQ = ""
OUTPUT_FILE = "simba_results.csv"
KAPPA = 4.0 

def main():
    print("--- SIMBA-Infer 2.0 Starting Pipeline ---")
    
    # Phase 1 Counting mutations with HKY85 model
    print("\n[Phase 1] Counting mutations with HKY85 model")
    try:
        counts_df = counting.process_alignment(INPUT_FASTA, REFERENCE_SEQ, kappa=KAPPA)
        print(f"Counting complete. Analyzed {len(counts_df)} codon sites.")
    except Exception as e:
        print(f"Error in Phase 1 {e}")
        return

    # Phase 2 Running Bayesian Global Grid Inference
    print("\n[Phase 2] Running Bayesian Global Grid Inference")
    try:
        results_df = inference.run_inference(counts_df)
        print("Inference complete.")
    except Exception as e:
        print(f"Error in Phase 2 {e}")
        return

    # Phase 3 Save and Report
    results_df.to_csv(OUTPUT_FILE, index=False)
    
    pos_sites = results_df[results_df['Prob_Positive_Selection'] > 0.95]
    print(f"\nAnalysis Complete")
    print(f"Results saved to {OUTPUT_FILE}")
    print(f"Identified {len(pos_sites)} sites under strong positive selection")
    
    if len(pos_sites) > 0:
        print("Top Selection Sites")
        print(pos_sites[['Codon_Pos', 'Beta_Mean', 'Prob_Positive_Selection']].head())

if __name__ == "__main__":
    main()


# import visualise
visualise.generate_visuals(OUTPUT_FILE)